task V4_015 {
  require cap(water_sensor)
  require cap(temperature_sensor)
  require cap(relay1)

  if read(water_sensor) > 40 and read(temperature_sensor) > 20 then
    {
      set relay1 = 1
      repeat 2 times
        {
          wait 1000ms
          set relay1 = !relay1
        }
    }
  else
    {
      set relay1 = 0
    }

  halt
}
